<?php
namespace App\Http\Controllers;use App\Models\GamePackage;use App\Models\TopupOrder;use App\Services\OrderService;use App\Services\WalletService;use Illuminate\Http\Request;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Str;class OrderController extends Controller{public function store(Request $request,WalletService $wallet,OrderService $orders){$data=$request->validate(['game_package_id'=>'required|exists:game_packages,id','player_id'=>'required|max:100','server_id'=>'nullable|max:100','payment_mode'=>'required|in:wallet,online']);$package=GamePackage::with('game','provider')->findOrFail($data['game_package_id']);if($package->game->requires_server_id&&empty($data['server_id']))return back()->withInput()->with('error','Server ID is required.');$order=TopupOrder::create(['order_no'=>'GT'.date('YmdHis').strtoupper(Str::random(4)),'user_id'=>Auth::id(),'game_id'=>$package->game_id,'game_package_id'=>$package->id,'provider_id'=>$package->provider_id,'payment_mode'=>$data['payment_mode'],'payment_status'=>$data['payment_mode']=='wallet'?'paid':'unpaid','order_status'=>$data['payment_mode']=='wallet'?'processing':'pending_payment','provider_status'=>'pending','player_id'=>$data['player_id'],'server_id'=>$data['server_id']??null,'amount_minor'=>$package->price_minor,'currency_code'=>$package->currency_code,'message'=>'Order created.']);if($data['payment_mode']==='wallet'){$wallet->debit(Auth::id(),$order->amount_minor,'Top-up order '.$order->order_no,'topup_order',(string)$order->id);$orders->processProvider($order);return redirect()->route('orders.index')->with('success','Order placed successfully.');}return redirect()->route('payment.direct',['order_id'=>$order->id]);}public function index(){$orders=TopupOrder::with('game','package')->where('user_id',Auth::id())->latest()->paginate(10);return view('orders.index',compact('orders'));}}
